#!/usr/bin/env python3\nimport json\nimport os\n\n# New translations for Groups component\ntranslations = {\n    \"pt\": {\n        \"back\": \"Voltar\",\n        \"members_one\": \"membro\",\n        \"members_other\": \"membros\",\n        \"joinGroup\": \"Participar do Grupo\",\n        \"leaveGroup\": \"Sair do Grupo\",\n        \"inputPlaceholder\": \"Publicar algo...\",\n        \"createGroup\": \"Criar Grupo\",\n        \"communionTitle\": \"👥 Caminhe na Fé em Comunidade\",\n        \"communionDesc\": \"Os grupos são espaços para compartilhar, aprender e crescer juntos na fé. Crie ou participe de grupos de estudo bíblico, oração, louvor ou qualquer tema que una irmãos em Cristo.\",\n        \"communionVerse\": \"Não deixemos de congregar-nos, como é costume de alguns; antes, façamos admoestações e tanto mais quanto vedes que o Dia se aproxima.\" — Hebreus 10:25\",\n        \"loading\": \"Carregando...\",\n        \"noGroups\": \"Nenhum grupo encontrado.\",\n        \"createFirst\": \"Seja o primeiro a criar um!\",\n        \"timeAgo\": {\n            \"now\": \"Agora\"\n        },\n        \"createForm\": {\n            \"submit\": \"Criar Novo Grupo\",\n            \"name\": \"Nome do Grupo\",\n            \"desc\": \"Descrição (opcional)\",\n            \"cancel\": \"Cancelar\"\n        }\n    },\n    \"en\": {\n        \"back\": \"Back\",\n        \"members_one\": \"member\",\n        \"members_other\": \"members\",\n        \"joinGroup\": \"Join Group\",\n        \"leaveGroup\": \"Leave Group\",\n        \"inputPlaceholder\": \"Post something...\",\n        \"createGroup\": \"Create Group\",\n        \"communionTitle\": \"👥 Walk in Faith in Community\",\n        \"communionDesc\": \"Groups are spaces to share, learn, and grow together in faith. Create or join Bible study, prayer, praise, youth, or any other topic that unites brothers and sisters in Christ.\",\n        \"communionVerse\": \"Let us not give up meeting together, as some are in the habit of doing, but let us encourage one another—and all the more as you see the Day approaching.\" — Hebrews 10:25\",\n        \"loading\": \"Loading...\",\n        \"noGroups\": \"No groups found.\",\n        \"createFirst\": \"Be the first to create one!\",\n        \"timeAgo\": {\n            \"now\": \"Now\"\n        },\n        \"createForm\": {\n            \"submit\": \"Create New Group\",\n            \"name\": \"Group Name\",\n            \"desc\": \"Description (optional)\",\n            \"cancel\": \"Cancel\"\n        }\n    },\n    \"es\": {\n        \"back\": \"Volver\",\n        \"members_one\": \"miembro\",\n        \"members_other\": \"miembros\",\n        \"joinGroup\": \"Unirse al Grupo\",\n        \"leaveGroup\": \"Abandonar Grupo\",\n        \"inputPlaceholder\": \"Publica algo...\",\n        \"createGroup\": \"Crear Grupo\",\n        \"communionTitle\": \"👥 Camina en Fe en Comunidad\",\n        \"communionDesc\": \"Los grupos son espacios para compartir, aprender y crecer juntos en la fe. Crea o únete a grupos de estudio bíblico, oración, alabanza o cualquier otro tema que una a hermanos en Cristo.\",\n        \"communionVerse\": \"No dejemos de congregarnos, como acostumbran a hacer algunos, sino animémonos unos a otros, y con mucha más razón ahora que vemos que el día se acerca.\" — Hebreos 10:25\",\n        \"loading\": \"Cargando...\",\n        \"noGroups\": \"No se encontraron grupos.\",\n        \"createFirst\": \"¡Sé el primero en crear uno!\",\n        \"timeAgo\": {\n            \"now\": \"Ahora\"\n        },\n        \"createForm\": {\n            \"submit\": \"Crear Nuevo Grupo\",\n            \"name\": \"Nombre del Grupo\",\n            \"desc\": \"Descripción (opcional)\",\n            \"cancel\": \"Cancelar\"\n        }\n    },\n    \"de\": {\n        \"back\": \"Zurück\",\n        \"members_one\": \"Mitglied\",\n        \"members_other\": \"Mitglieder\",\n        \"joinGroup\": \"Gruppe beitreten\",\n        \"leaveGroup\": \"Gruppe verlassen\",\n        \"inputPlaceholder\": \"Etwas posten...\",\n        \"createGroup\": \"Gruppe erstellen\",\n        \"communionTitle\": \"👥 Wandle im Glauben in Gemeinschaft\",\n        \"communionDesc\": \"Gruppen sind Orte, um im Glauben zu teilen, zu lernen und gemeinsam zu wachsen. Erstelle oder trete Bibelstudien-, Gebets-, Lobpreis-, Jugend-, Paar- oder anderen Themengruppen bei, die Geschwister in Christus vereinen.\",\n        \"communionVerse\": \"Lasst uns nicht die Versammlung der Gemeinde vernachlässigen, wie es einige tun, sondern lasst uns einander ermutigen, und das umso mehr, als ihr seht, dass der Tag naht.\" — Hebräer 10:25\",\n        \"loading\": \"Lädt...\",\n        \"noGroups\": \"Keine Gruppen gefunden.\",\n        \"createFirst\": \"Sei der Erste, der eine erstellt!\",\n        \"timeAgo\": {\n            \"now\": \"Jetzt\"\n        },\n        \"createForm\": {\n            \"submit\": \"Neue Gruppe erstellen\",\n            \"name\": \"Gruppenname\",\n            \"desc\": \"Beschreibung (optional)\",\n            \"cancel\": \"Abbrechen\"\n        }\n    },\n    \"fr\": {\n        \"back\": \"Retour\",\n        \"members_one\": \"membre\",\n        \"members_other\": \"membres\",\n        \"joinGroup\": \"Rejoindre le groupe\",\n        \"leaveGroup\": \"Quitter le groupe\",\n        \"inputPlaceholder\": \"Publier quelque chose...\",\n        \"createGroup\": \"Créer un groupe\",\n        \"communionTitle\": \"👥 Marchez dans la foi en communauté\",\n        \"communionDesc\": \"Les groupes sont des espaces pour partager, apprendre et grandir ensemble dans la foi. Créez ou rejoignez des groupes d\'étude biblique, de prière, de louange, de jeunes ou tout autre thème qui unit les frères et sœurs en Christ.\",\n        \"communionVerse\": \"N\'abandonnons pas notre assemblée, comme c\'est la coutume de quelques-uns, mais exhortons-nous mutuellement, et cela d\'autant plus que vous voyez le jour approcher.\" — Hébreux 10:25\",\n        \"loading\": \"Chargement...\",\n        \"noGroups\": \"Aucun groupe trouvé.\",\n        \"createFirst\": \"Soyez le premier à en créer un !\",\n        \"timeAgo\": {\n            \"now\": \"Maintenant\"\n        },\n        \"createForm\": {\n            \"submit\": \"Créer un nouveau groupe\",\            \"name\": \"Nom du groupe\",\n            \"desc\": \"Description (optionnel)\",\n            \"cancel\": \"Annuler\"\n        }\n    },\n    \"ro\": {\n        \"back\": \"Înapoi\",\n        \"members_one\": \"membru\",\n        \"members_other\": \"membri\",\n        \"joinGroup\": \"Alătură-te grupului\",\n        \"leaveGroup\": \"Părăsește grupul\",\n        \"inputPlaceholder\": \"Postează ceva...\",\n        \"createGroup\": \"Creează grup\",\n        \"communionTitle\": \"👥 Mergi în credință în comunitate\",\n        \"communionDesc\": \"Grupurile sunt spații pentru a împărtăși, a învăța și a crește împreună în credință. Creează sau alătură-te unor grupuri de studiu biblic, rugăciune, laudă, tineri sau orice altă temă care unește frații și surorile în Hristos.\",\n        \"communionVerse\": \"Să nu părăsim adunarea noastră, cum au unii obicei, ci să ne îmbărbătăm unii pe alții, și cu atât mai mult, cu cât vedeți că ziua se apropie.\" — Evrei 10:25\",\n        \"loading\": \"Se încarcă...\",\n        \"noGroups\": \"Niciun grup găsit.\",\n        \"createFirst\": \"Fii primul care creează unul!\",\n        \"timeAgo\": {\n            \"now\": \"Acum\"\n        },\n        \"createForm\": {\n            \"submit\": \"Creează un grup nou\",\n            \"name\": \"Numele grupului\",\n            \"desc\": \"Descriere (opțional)\",\n            \"cancel\": \"Anulează\"\n        }\n    },\n    \"ru\": {\n        \"back\": \"Назад\",\n        \"members_one\": \"участник\",\n        \"members_other\": \"участники\",\n        \"joinGroup\": \"Присоединиться к группе\",\n        \"leaveGroup\": \"Покинуть группу\",\n        \"inputPlaceholder\": \"Опубликовать что-нибудь...\",\n        \"createGroup\": \"Создать группу\",\n        \"communionTitle\": \"👥 Идите в вере в общине\",\n        \"communionDesc\": \"Группы - это места для общения, обучения и совместного роста в вере. Создавайте или присоединяйтесь к группам по изучению Библии, молитве, прославлению, молодежным или любым другим темам, которые объединяют братьев и сестер во Христе.\",\n        \"communionVerse\": \"Не будем оставлять собрания нашего, как есть у некоторых обычай; но будем наставлять друг друга, и тем более, чем более усматриваете приближение того дня.\" — Евреям 10:25\",\n        \"loading\": \"Загрузка...\",\n        \"noGroups\": \"Группы не найдены.\",\n        \"createFirst\": \"Будьте первым, кто создаст!\",\n        \"timeAgo\": {\n            \"now\": \"Сейчас\"\n        },\n        \"createForm\": {\n            \"submit\": \"Создать новую группу\",\n            \"name\": \"Название группы\",\n            \"desc\": \"Описание (необязательно)\",\n            \"cancel\": \"Отмена\"\n        }\n    }\n}\n\nbase_path = \"frontend/src/i18n/\"\nlang_files = [f for f f in os.listdir(base_path) if f.endswith(\".json\")]\n\nprint(\"Updating Groups translations in all language files...\")\n\nfor filename in lang_files:\n    file_path = os.path.join(base_path, filename)\n    print(f\"Processing {file_path}...\")\n    try:\n        with open(file_path, \'r\', encoding=\'utf-8\') as f:\n            data = json.load(f)\n        \n        if \'groups\' not in data:\n            data[\'groups\'] = {}\n        \n        # Add new keys to groups section\n        data[\'groups\'].update(translations[filename[:2]])\n        \n        with open(file_path, \'w\', encoding=\'utf-8\') as f:\n            json.dump(data, f, ensure_ascii=False, indent=4)\n        \n        print(f\"[OK] {filename} updated successfully\")\n    \n    except Exception as e:\n        print(f\"[ERROR] Unknown error with {filename}: {e}\")\n\nprint(\"\\nAll language files processed!\")\n